// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimplePermission {
    struct Capability {
        uint maxAmount;
        uint expiry;
        bool active;
    }

    mapping(address => Capability) public permissions;

    function grantPermission(address agent, uint maxAmount, uint duration) external {
        permissions[agent] = Capability({
            maxAmount: maxAmount,
            expiry: block.timestamp + duration,
            active: true
        });
    }

    modifier onlyPermitted(uint amount) {
        Capability storage cap = permissions[msg.sender];
        require(cap.active, "No active permission");
        require(block.timestamp < cap.expiry, "Permission expired");
        require(amount <= cap.maxAmount, "Exceeds permitted amount");
        _;
    }

    function spendWithPermission(uint amount) external onlyPermitted(amount) {
        // In a real contract, you would transfer tokens or perform the action here.
        // For the assessment, we simply accept the call if checks pass.
    }

    function revokePermission(address agent) external {
        permissions[agent].active = false;
    }
}
